// DC Protocol: Process-level error handlers to prevent silent crashes in production
process.on('uncaughtException', (err) => {
  console.error('❌ [DC-ERR-001] Uncaught Exception:', err.message);
  console.error(err.stack);
});

process.on('unhandledRejection', (reason, promise) => {
  console.error('❌ [DC-ERR-002] Unhandled Rejection at:', promise);
  console.error('Reason:', reason);
});

// SERVER-SIDE JavaScript String Escaping - For embedding values in inline <script> tags
function escapeJSServer(str) {
  if (!str) return '';
  return String(str)
    .replace(/\\/g, '\\\\')   // Backslash
    .replace(/'/g, "\\\'")     // Single quote  
    .replace(/"/g, '\\\\"')     // Double quote
    .replace(/\n/g, '\\n')    // Newline
    .replace(/\r/g, '\\r')    // Carriage return
    .replace(/\t/g, '\\t');   // Tab
}

// DC Protocol Dec 23, 2025: Filter out body-level CSS rules that conflict with admin layout
// Prevents standalone page styles from overriding admin template background/layout
function filterBodyStyles(cssString) {
  if (!cssString) return '';
  return cssString.replace(/body\s*\{[^}]*\}/gi, '/* body styles removed by DC Protocol */');
}

// CLIENT-SIDE Escaping Utilities (embedded in HTML for browser use)
// HTML Escaping Utility - Prevents XSS and syntax errors
function escapeHTML(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

// JavaScript String Escaping - For use in onclick handlers and JS strings
function escapeJS(str) {
  if (!str) return '';
  return String(str)
    .replace(/\\/g, '\\\\')   // Backslash
    .replace(/'/g, "\\\'")     // Single quote  
    .replace(/"/g, '\\\\"')     // Double quote
    .replace(/\n/g, '\\n')    // Newline
    .replace(/\r/g, '\\r')    // Carriage return
    .replace(/\t/g, '\\t');   // Tab
}

