// DC Protocol: Server-side fetch with retry for production resilience (VM startup, republish)
async function fetchWithRetryServer(url, options = {}, maxRetries = 5, baseDelay = 1000) {
  for (let i = 0; i < maxRetries; i++) {
    try {
      const response = await fetch(url, { ...options, timeout: 10000 });
      if (response.ok || response.status < 500) {
        return response;
      }
      console.warn(`[DC-RETRY] Attempt ${i + 1}/${maxRetries} for ${url} (status: ${response.status})`);
    } catch (error) {
      console.warn(`[DC-RETRY] Attempt ${i + 1}/${maxRetries} for ${url}: ${error.message}`);
    }
    if (i < maxRetries - 1) {
      const delay = baseDelay * Math.pow(2, i);
      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }
  throw new Error(`Failed after ${maxRetries} retries`);
}
// DC Protocol: Sanitize host header (production can have comma-separated domains)
function getSafeHost(req) {
  const host = req.headers.host || 'localhost';
  // REPLIT_DOMAINS can contain multiple domains separated by commas
  // e.g., "newbev.replit.app,mnr.manthraev.com"
  // We only need the first one for URL construction
  return host.split(',')[0].trim();
}

// DC Protocol (Apr 2026): mnrteam.com is the unified portal domain for all portals
// (staff, partner, RVZ, MNR member). myntreal.com is decommissioned.
// Domain-scope guard is retired — getRequestScope always returns 'all'.
const _STAFF_DOMAIN = 'mnrteam.com';
const _MNR_DOMAIN   = 'mnrteam.com';

function getRequestScope(req) {
  // DC Protocol Apr 2026: unified domain — no cross-domain routing applied
  return 'all';
}

// DC Protocol (Apr 2026): Domain guard retired — mnrteam.com serves all portals.
// These prefix lists are kept for reference but are never evaluated (scope='all' always).
// '/dashboard' is intentionally EXCLUDED — it is a shared routing hub for all roles.
const _MNR_ONLY_PREFIXES = [
  '/login', '/user', '/user-home',
  '/member-welcome', '/signup',
  '/mnrguide', '/mnruserguide', '/mnrvalidation', '/mnrui'
];

// URL prefixes that belong to the staff / business portal (all served from mnrteam.com)
const _STAFF_ONLY_PREFIXES = [
  '/staff/', '/partner/', '/rvz/', '/vgk/'
];

const ROUTE_MAP_ENABLED = false;

// Route map: Declarative route definitions
// Structure: { path: string, handler: string (legacy placeholder), authRequired: boolean }
const ROUTE_MAP = {};

/**
 * Normalize and resolve route from request
 * @param {http.IncomingMessage} req - HTTP request
 * @returns {object|null} - Route config or null if not found
 */
function resolveRoute(req) {
  if (!ROUTE_MAP_ENABLED) return null;
  // Parse URL and strip query parameters
  const urlObj = new URL(req.url, `http://${getSafeHost(req)}`);
  let pathname = urlObj.pathname;
  // Normalize path: ensure no trailing slash (except root)
  if (pathname.length > 1 && pathname.endsWith('/')) {
    pathname = pathname.slice(0, -1);
  }
  // Look up in route map
  return ROUTE_MAP[pathname] || null;
}

