// Simple session storage (in production this would be in a database)
const activeSessions = new Set();
// Build ID for cache busting
const BUILD_ID = Date.now(); // Dynamic cache-busting on server restart (Dec 30, 2025)
console.log(`🔑 Build ID: ${BUILD_ID}`);

// DC Protocol: Strict no-cache headers with ETag for staff HTML pages
// Prevents browser caching issues that cause stale content display
function getStrictNoCacheHeaders() {
  return {
    'Content-Type': 'text/html; charset=utf-8',
    'Cache-Control': 'no-store, no-cache, max-age=0, must-revalidate, proxy-revalidate',
    'Pragma': 'no-cache',
    'Expires': '0',
    'ETag': `"${BUILD_ID}"`,
    'Surrogate-Control': 'no-store'
  };
}

// Session role cache: Map<sessionToken, {userId, authLevel}>
const sessionRoleCache = new Map();

// DC Protocol (Dec 28, 2025): Staff Role to RBAC Level Mapping
// Maps staff role_codes to equivalent RBAC authorization levels
const STAFF_ROLE_MAPPINGS = {
  'vgk4u': 'RVZ ID',              // VGK4U Supreme -> Full access (RVZ ID level)
  'key_leadership': 'Super Admin', // Key Leadership -> Super Admin
  'leadership_role': 'Super Admin', // Leadership Role -> Super Admin
  'hr': 'Admin',                   // HR -> Admin
  'ea': 'Admin',                   // Executive Assistant -> Admin
  'accounts': 'Finance Admin',     // Accounts -> Finance Admin
  'manager': 'Admin',              // Manager -> Admin
  'team_leader': 'Admin',          // Team Leader -> Admin
  'senior_executive': 'Admin',     // Senior Executive -> Admin
  'supervisor': 'Admin',           // Supervisor -> Admin
  'junior_executive': 'Member',    // Junior Executive -> Member level
  'employee': 'Member',            // Basic Employee -> Member level
  'freelancer_manager': 'Admin',   // Freelancer Manager -> Admin
};

// Helper function to map staff role_code to authLevel
function getStaffAuthLevel(roleCode) {
  if (!roleCode) return 'Member';
  return STAFF_ROLE_MAPPINGS[roleCode] || 'Member';
}

// DC Protocol (Jan 22, 2026): Load Menu Master for route-to-menu_code mapping
const MENU_MASTER = require('./public/js/menu-master.js').MENU_MASTER;
const { findMenuByRoute: menuMasterFindByRoute } = require('./public/js/menu-master.js');

// DC Protocol (Jan 22, 2026): Supreme roles that bypass access control
const SUPREME_STAFF_TYPES = ['VGK4U_SUPREME', 'RVZ_SUPREME', 'VGK4U', 'vgk4u', 'VGK4U_EA'];
const FULL_ACCESS_ROLES = ['vgk4u', 'ea', 'hr', 'accounts', 'key_leadership', 'kl'];

// DC Protocol (Jan 22, 2026): Check if staff user has access to a specific route
// Returns: { allowed: boolean, reason: string }
async function checkStaffMenuAccess(staffToken, requestedRoute, userData = null) {
  try {
    // Step 1: If no token, deny access
    if (!staffToken) {
      console.log('[DC-ROUTE] /staff/mnr/users - No token, redirecting to login');
      return { allowed: false, reason: 'NO_TOKEN', redirect: '/staff/login' };
    }

    // Step 2: Get user data if not provided
    if (!userData) {
      try {
        const response = await fetch(BACKEND_URL_SERVER + '/api/v1/staff/auth/me', {
          headers: { 'Authorization': `Bearer ${staffToken}` }
        });
        if (response.ok) {
          const responseData = await response.json();
          // Handle both direct and nested response formats (auth/me returns employee object)
          userData = responseData.employee || responseData;
        } else {
          return { allowed: false, reason: 'AUTH_FAILED', redirect: '/staff/login' };
        }
      } catch (e) {
        console.error('[DC-ACCESS] Auth check failed:', e.message);
        return { allowed: false, reason: 'AUTH_ERROR', redirect: '/staff/login' };
      }
    }

    // Step 3: Check if user is Supreme role (bypass all access control)
    const staffType = userData.staff_type || userData.role_code || '';
    if (SUPREME_STAFF_TYPES.some(s => staffType.toUpperCase().includes(s.toUpperCase()))) {
      return { allowed: true, reason: 'SUPREME_BYPASS' };
    }

    // Step 3b: Check if user has a full-access role (EA, HR, Accounts) - bypass menu restrictions
    const roleCode = (userData.role_code || userData.role?.role_code || '').toLowerCase();
    if (roleCode && FULL_ACCESS_ROLES.includes(roleCode)) {
      return { allowed: true, reason: 'FULL_ACCESS_ROLE_BYPASS' };
    }

    // Step 4: Normalize route for lookup
    const normalizedRoute = requestedRoute.toLowerCase().split('?')[0];

    // Step 4b: Find menu_code for this route from Menu Master
    const menuItem = menuMasterFindByRoute(normalizedRoute);
    if (!menuItem) {
      // Route not in menu master - allow (might be a utility page or not menu-controlled)
      console.log('[DC-ACCESS] Route ' + normalizedRoute + ' not in Menu Master - allowing');
      return { allowed: true, reason: 'NOT_IN_MENU_MASTER' };
    }

    // Step 6: Get user's allowed menus from API
    try {
      const menusResponse = await fetch(BACKEND_URL_SERVER + '/api/v1/staff/menu-settings/my-menus?unified=true', {
        headers: { 'Authorization': `Bearer ${staffToken}` }
      });
      
      if (!menusResponse.ok) {
        console.warn('[DC-ACCESS] my-menus API failed, denying access');
        return { allowed: false, reason: 'MENU_API_FAILED', redirect: '/staff/access-denied' };
      }

      const menusData = await menusResponse.json();
      
      // Check if user has this route in their allowed menus
      const allowedRoutes = (menusData.menus || []).map(m => m.route_path ? m.route_path.toLowerCase() : null).filter(Boolean);
      const allowedMenuCodes = (menusData.menus || []).map(m => m.menu_code ? m.menu_code.toUpperCase() : null).filter(Boolean);

      // Check by route_path or menu_code (with flexible matching)
      const hasAccessByRoute = allowedRoutes.includes(normalizedRoute);
      const requestedCode = menuItem.menu_code ? menuItem.menu_code.toUpperCase() : '';
      const hasAccessByCode = allowedMenuCodes.includes(requestedCode);
      // Flexible code matching: MENU_MASTER uses SHORT codes (e.g., MY_TIMESHEET)
      // Registry uses PREFIXED codes (e.g., STAFF_MY_TIMESHEET). Match both ways.
      const hasAccessByFlexCode = !hasAccessByCode && requestedCode && allowedMenuCodes.some(ac => {
        return ac === 'STAFF_' + requestedCode || ac === requestedCode.replace(/^STAFF_/, '');
      });

      if (hasAccessByRoute || hasAccessByCode || hasAccessByFlexCode) {
        return { allowed: true, reason: hasAccessByFlexCode ? 'MENU_GRANTED_FLEX' : 'MENU_GRANTED' };
      } else {
        console.log('[DC-ACCESS] DENIED: ' + (userData.emp_code || 'unknown') + ' tried ' + normalizedRoute + ' (menu_code: ' + menuItem.menu_code + ')');
        return { allowed: false, reason: 'NOT_IN_ALLOWED_MENUS', redirect: '/staff/access-denied' };
      }
    } catch (e) {
      console.error('[DC-ACCESS] Menu check failed:', e.message);
      // On error, deny access for safety
      return { allowed: false, reason: 'MENU_CHECK_ERROR', redirect: '/staff/access-denied' };
    }
  } catch (e) {
    console.error('[DC-ACCESS] Access check exception:', e.message);
    return { allowed: false, reason: 'EXCEPTION', redirect: '/staff/login' };
  }
}


// DC Protocol (Dec 23, 2025): Preloaded HTML Cache for Production Stability
// Prevents EIO filesystem errors during autoscale cold starts
// DC Protocol (Mar 2026): Converted to async to never block server.listen() on cold starts
const htmlCache = new Map();
const fsPromises = require('fs').promises;

async function preloadCriticalHtmlFiles() {
  let rootCount = 0;
  try {
    const rootHtmlFiles = fs.readdirSync(__dirname).filter(f => f.endsWith('.html'));
    for (const fileName of rootHtmlFiles) {
      const filePath = path.join(__dirname, fileName);
      try {
        const content = await fsPromises.readFile(filePath, 'utf8');
        htmlCache.set(fileName, content);
        rootCount++;
      } catch (err) {
        console.error(`⚠️ [DC_CACHE] Failed to preload ${fileName}: ${err.message}`);
      }
    }
    console.log(`📦 [DC_CACHE] Preloaded ${rootCount} root HTML files`);
  } catch (err) {
    console.error(`⚠️ [DC_CACHE] Failed to scan root dir: ${err.message}`);
  }

  let templateCount = 0;
  const templatesDir = path.join(__dirname, 'templates');
  try {
    if (fs.existsSync(templatesDir)) {
      const templateFiles = fs.readdirSync(templatesDir).filter(f => f.endsWith('.html'));
      for (const fileName of templateFiles) {
        const filePath = path.join(templatesDir, fileName);
        try {
          const content = await fsPromises.readFile(filePath, 'utf8');
          htmlCache.set(filePath, content);
          templateCount++;
        } catch (err) {
          console.error(`⚠️ [DC_CACHE] Failed to preload template ${fileName}: ${err.message}`);
        }
      }
      console.log(`📦 [DC_CACHE] Preloaded ${templateCount} template HTML files`);
    }
  } catch (err) {
    console.error(`⚠️ [DC_CACHE] Failed to scan templates dir: ${err.message}`);
  }

  const subdirs = ['templates/rvz', 'templates/vgk'];
  for (const subdir of subdirs) {
    const subDirPath = path.join(__dirname, subdir);
    try {
      if (fs.existsSync(subDirPath)) {
        const subFiles = fs.readdirSync(subDirPath).filter(f => f.endsWith('.html'));
        for (const fileName of subFiles) {
          const filePath = path.join(subDirPath, fileName);
          try {
            const content = await fsPromises.readFile(filePath, 'utf8');
            htmlCache.set(filePath, content);
          } catch (err) {}
        }
        console.log(`📦 [DC_CACHE] Preloaded ${subFiles.length} files from ${subdir}/`);
      }
    } catch (err) {}
  }

  // DC Protocol (Apr 2026): Pre-cache public/landing.html to prevent EIO errors in production
  const landingPath = path.join(__dirname, 'public', 'landing.html');
  try {
    const landingContent = await fsPromises.readFile(landingPath, 'utf8');
    htmlCache.set('public/landing.html', landingContent);
    console.log('📦 [DC_CACHE] Preloaded public/landing.html');
  } catch (err) {
    console.error('⚠️ [DC_CACHE] Failed to preload public/landing.html:', err.message);
  }

  console.log(`📦 [DC_CACHE] Total cached: ${htmlCache.size} HTML files`);
}

// DC_CACHE_WATCHER: Auto-invalidate htmlCache when HTML files change on disk
// Ensures edited HTML files are served immediately without server restart
function setupHtmlCacheWatcher() {
  const watchTargets = [
    { dir: __dirname, useFullPath: false },
    { dir: path.join(__dirname, 'public'), useFullPath: true },
    { dir: path.join(__dirname, 'templates'), useFullPath: true },
    { dir: path.join(__dirname, 'templates/rvz'), useFullPath: true },
    { dir: path.join(__dirname, 'templates/vgk'), useFullPath: true }
  ];
  watchTargets.forEach(({ dir, useFullPath }) => {
    if (!fs.existsSync(dir)) return;
    try {
      fs.watch(dir, { persistent: false }, (eventType, filename) => {
        if (!filename || !filename.endsWith('.html')) return;
        const fullPath = path.join(dir, filename);
        const deleted1 = htmlCache.delete(filename);
        const deleted2 = htmlCache.delete(fullPath);
        if (deleted1 || deleted2) {
          console.log(`🔄 [DC_CACHE] Cache invalidated: ${filename} (will reload from disk on next request)`);
        }
      });
    } catch (err) {
      console.warn(`⚠️ [DC_CACHE] Watcher failed for ${dir}: ${err.message}`);
    }
  });
  console.log('👁️  [DC_CACHE] HTML file watcher active — edits take effect immediately');
}

// DC_MOBILE_CSS: Inject mobile-responsive CSS into all HTML pages
const MOBILE_CSS_LINK = '<link rel="stylesheet" href="/public/css/mobile-responsive.css">';
function injectMobileCss(html) {
  if (html.includes('mobile-responsive.css')) return html;
  if (html.includes('</head>')) {
    return html.replace('</head>', MOBILE_CSS_LINK + '\n</head>');
  }
  return html;
}

// Serve HTML from cache with filesystem fallback and retry
function serveCachedHtml(res, fileName, buildId) {
  // Try cache first
  if (htmlCache.has(fileName)) {
    let html = htmlCache.get(fileName).replace(/\?v=\d+/g, `?v=${buildId}`);
    html = injectMobileCss(html);
    html = injectVgkAssistant(html);
    res.writeHead(200, {
      'Content-Type': 'text/html',
      'Cache-Control': 'no-cache, no-store, must-revalidate'
    });
    res.end(html);
    return true;
  }
  
  // Fallback to filesystem with retry
  const filePath = path.join(__dirname, fileName);
  let retries = 2;
  
  function tryRead() {
    fs.readFile(filePath, 'utf8', (err, data) => {
      if (err) {
        if (retries > 0 && err.code === 'EIO') {
          retries--;
          console.log(`🔄 [DC_CACHE] Retry reading ${fileName} (${retries} left)`);
          setTimeout(tryRead, 100);
          return;
        }
        console.error(`❌ [DC_CACHE] Failed to read ${fileName}: ${err.code} - ${err.message}`);
        res.writeHead(500, { 'Content-Type': 'text/html' });
        res.end('<html><body><h1>Temporary Error</h1><p>Please refresh the page.</p><script>setTimeout(function(){location.reload()},2000)</script></body></html>');
        return;
      }
      // Cache for next time
      htmlCache.set(fileName, data);
      let html = data.replace(/\?v=\d+/g, `?v=${buildId}`);
      html = injectMobileCss(html);
      html = injectVgkAssistant(html);
      res.writeHead(200, {
        'Content-Type': 'text/html',
        'Cache-Control': 'no-cache, no-store, must-revalidate'
      });
      res.end(html);
    });
  }
  
  tryRead();
  return true;
}
// Get cached HTML content for complex route processing (DC Protocol Dec 24, 2025)
// Returns content string or null if not available
function getCachedHtmlContent(fileName) {
  if (htmlCache.has(fileName)) {
    return htmlCache.get(fileName);
  }
  
  // Fallback: Try synchronous read with retry for cold start
  const filePath = path.join(__dirname, fileName);
  for (let retry = 0; retry < 3; retry++) {
    try {
      const content = fs.readFileSync(filePath, 'utf8');
      htmlCache.set(fileName, content);
      console.log(`📦 [DC_CACHE] Loaded on demand: ${fileName} (${content.length} bytes)`);
      return content;
    } catch (err) {
      if (err.code === 'EIO' && retry < 2) {
        console.log(`🔄 [DC_CACHE] Retry ${retry + 1}/3 for ${fileName}`);
        continue;
      }
      console.error(`❌ [DC_CACHE] Failed to read ${fileName}: ${err.code}`);
      return null;
    }
  }
  return null;
}



// DC Protocol (Feb 2026): EIO-safe file read with retry and caching
// Replaces raw fs.readFile for template routes to prevent "Page not found" in production
function readFileWithRetry(filePath, callback, maxRetries = 3) {
  const cacheKey = filePath;
  const isHtml = filePath.endsWith('.html');
  if (htmlCache.has(cacheKey)) {
    const raw = htmlCache.get(cacheKey);
    return callback(null, isHtml ? injectVgkAssistant(raw) : raw);
  }
  let attempt = 0;
  function tryRead() {
    fs.readFile(filePath, 'utf8', (err, data) => {
      if (err) {
        attempt++;
        if (err.code === 'EIO' && attempt < maxRetries) {
          console.log(`[DC-EIO-RETRY] Retry ${attempt}/${maxRetries} for ${path.basename(filePath)}`);
          setTimeout(tryRead, 150 * attempt);
          return;
        }
        console.error(`[DC-EIO-FAIL] Failed to read ${path.basename(filePath)} after ${attempt} attempts: ${err.code} - ${err.message}`);
        return callback(err, null);
      }
      htmlCache.set(cacheKey, data);
      callback(null, isHtml ? injectVgkAssistant(data) : data);
    });
  }
  tryRead();
}

