// DC Protocol (Apr 21, 2026): Global VGK Assistant / VGKFieldVoice injection
// Injects vgk_assistant.js into every HTML page that doesn't already have it.
// Uses lastIndexOf('</body>') — same safe pattern as NDA injection.
function injectVgkAssistant(html) {
  if (!html) return html;
  const lastBodyIdx = html.lastIndexOf('</body>');
  if (lastBodyIdx === -1) return html;
  const toInject = [];
  if (!html.includes('/vgk_assistant.js')) {
    toInject.push('<script src="/vgk_assistant.js"></script>');
  }
  // DC-DRAFT-001: inject universal draft-manager on every page (skip login/public pages)
  if (!html.includes('/public/js/dc-draft-manager.js')) {
    toInject.push('<script src="/public/js/dc-draft-manager.js"></script>');
  }
  if (toInject.length === 0) return html;
  return html.slice(0, lastBodyIdx) + toInject.join('\n') + '\n</body>' + html.slice(lastBodyIdx + 7);
}

// DC Protocol (Dec 05, 2025): NDA Enforcement Script Injection Helper
// Injects NDA enforcement script into staff pages (except login page)
function injectNdaEnforcement(html) {
  // Skip injection for login page as it has its own NDA handling
  if (html.includes('Staff Portal Login') || html.includes('staff_login')) {
    return html;
  }
  
  // Inject NDA enforcement script before the LAST </body> tag.
  // DC Protocol (Mar 18, 2026): Must use lastIndexOf, not replace(), because
  // some pages (e.g. staff_vgk4u_po.html) embed </body></html> inside a JS
  // template literal string (for win.document.write). Using replace() would
  // inject a <script> tag inside that string, which introduces a </script>
  // that the browser's HTML parser uses to close the enclosing <script> block
  // prematurely, breaking all subsequent JS on the page.
  const ndaScript = '<script src="/public/js/nda-enforcement.js"></script>';
  const lastBodyIdx = html.lastIndexOf('</body>');
  if (lastBodyIdx !== -1) {
    return html.slice(0, lastBodyIdx) + ndaScript + '\n</body>' + html.slice(lastBodyIdx + 7);
  }
  
  return html;
}


// Helper function for serving HTML pages with auth checks
function serveHtmlPage(res, fileName, sessionToken, requiresAuth = true, rolesAllowed = null) {
  const filePath = path.join(__dirname, fileName);
  readFileWithRetry(filePath, (err, data) => {
    if (err) {
      res.writeHead(500, { 'Content-Type': 'text/plain' });
      res.end('Error loading page');
      return;
    }
    const html = injectVgkAssistant(data);
    res.writeHead(200, { 'Content-Type': 'text/html' });
    res.end(html);
  });
}
