    '/ev-company-warangal':                    'seo/ev-company-warangal.html',
    '/ev-company-karimnagar':                  'seo/ev-company-karimnagar.html',
    // City-level Solar pages — Andhra Pradesh
    '/solar-company-srikakulam':               'seo/solar-company-srikakulam.html',
    '/solar-company-vizianagaram':             'seo/solar-company-vizianagaram.html',
    '/solar-company-visakhapatnam':            'seo/solar-company-visakhapatnam.html',
