            document.getElementById('personalSummary').innerHTML = '<div class="alert alert-info">Sandbox Mode: Demo data displayed</div>';
            document.getElementById('mySummary').innerHTML = '<div class="alert alert-info">Sandbox Test Environment</div>';
            return;
