              const activePins = pins.filter(p => p.status === 'Active').length;
              const usedPins = pins.filter(p => p.status === 'Used' || p.activated_at).length;
              document.getElementById('activePinCount').textContent = activePins;
              document.getElementById('usedPinCount').textContent = usedPins;
              document.getElementById('totalPinCount').textContent = pins.length;
