                    html += '<div class="progress mb-2"><div class="progress-bar" style="width: ' + progress + '%">' + progress.toFixed(0) + '%</div></div>';
                    html += '<p><strong>Bonus Amount:</strong> ₹' + (award.bonus_amount || 0).toLocaleString() + '</p>';
                    html += '<p><strong>Paid:</strong> ₹' + (award.bonus_amount_paid || 0).toLocaleString() + '</p>';
