                    'onmouseover="highlightStars(this, ' + i + ')" ' +
                    'onmouseout="resetStars(' + announcement.id + ')" ' +
                    'onclick="openRatingLogin(' + announcement.id + ', ' + i + ')" ' +
                    'style="color: #d1d5db; font-size: 1rem; transition: color 0.2s; cursor: pointer;"></i>';
