            h += '<tr><td>Admin Pending</td><td class="text-warning">₹' + (summary.admin_pending_gross || summary.admin_pending || 0).toLocaleString() + '</td><td class="text-warning">₹' + (summary.admin_pending_net || 0).toLocaleString() + '</td></tr>';
