      h += '<table class="table table-sm table-bordered">';
      h += '<thead class="table-light"><tr><th>Income Type</th><th class="text-end">GROSS</th><th class="text-end">Mentorship Contribution Benefit</th><th class="text-end">Admin (8%)</th><th class="text-end">TDS (2%)</th><th class="text-end">Total Deducted</th><th class="text-end text-success">NET</th></tr></thead>';
      h += '<tbody>';
