        async function approveSA(id, action) {
          if (!confirm('Confirm ' + action + ' for withdrawal #' + id + '?')) {
            return;
          }
          try {
            const response = await fetch('/api/v1/withdrawals/superadmin/process-withdrawal/' + id, {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              credentials: 'include',
              body: JSON.stringify({ action: action })
            });
            if (response.ok) {
              alert('Success! Withdrawal ' + action + 'd');
              loadSuperAdminQueue();
            } else {
              alert('Error: ' + (await response.text()));
            }
          } catch (error) {
            alert('Error: ' + error.message);
          }
        }
        loadSuperAdminQueue();
