// DC_DIALER_WS_001: WebSocket proxy - forward backend WS upgrade requests to the API.
// Proxies /api/v1/**  and /ws/v1/** paths (covers dialer sync + future WS endpoints).
// Any other upgrade path gets a clean 426 rather than a silent socket close.
server.on('upgrade', (req, socket, head) => {
  const url = req.url || '';
  const isBackendWs = url.startsWith('/api/v1/') || url.startsWith('/ws/v1/');
  if (!isBackendWs) {
    socket.write('HTTP/1.1 426 Upgrade Required\r\nConnection: close\r\n\r\n');
    socket.destroy();
    return;
  }
  const net = require('net');
  const _wsBackendUrl = (process.env.BACKEND_URL || 'http://127.0.0.1:8000').replace(/^https?:\/\//, '').split(':');
  const _wsPort = parseInt(_wsBackendUrl[1]) || 8000;
  const _wsHost = _wsBackendUrl[0] || '127.0.0.1';
  const backendSocket = net.connect(_wsPort, _wsHost, () => {
    const CRLF = '\r\n';
    let headers = 'GET ' + url + ' HTTP/1.1' + CRLF;
    const rawHeaders = req.rawHeaders;
    for (let i = 0; i < rawHeaders.length; i += 2) {
      const name = rawHeaders[i];
      const val = rawHeaders[i + 1];
      if (name.toLowerCase() === 'host') {
        headers += 'Host: ' + _wsHost + ':' + _wsPort + CRLF;
      } else {
        headers += name + ': ' + val + CRLF;
      }
    }
    headers += CRLF;
    backendSocket.write(headers);
    if (head && head.length > 0) backendSocket.write(head);
    backendSocket.pipe(socket);
    socket.pipe(backendSocket);
  });
  backendSocket.on('error', (err) => {
    console.error('[DC_DIALER_WS] Backend WS proxy error:', err.message);
    socket.destroy();
  });
  socket.on('error', () => { backendSocket.destroy(); });
});

