  console.log(`📂 [DC_PATH_DEBUG] staff_login.html exists: ${require('fs').existsSync(require('path').join(__dirname, 'staff_login.html'))}`);
  console.log('📝 Available routes:');
  console.log('   / or /user -> Dashboard redirect');
  console.log('   /dashboard -> Main dashboard');
  console.log('   /user/awards -> Awards page');
  console.log('   /user/field-allowances -> Field allowances page');
  console.log('   /rvz/dashboard -> RVZ Supreme Admin Dashboard');
